/* Avatar component tokens — override these to customise avatars. */
:root {
  /* Per-size dimensions */
  --avatar-xs-size: 16px;
  --avatar-sm-size: 20px;
  --avatar-md-size: 24px;
  --avatar-lg-size: 28px;
  --avatar-xl-size: 32px;
  --avatar-2xl-size: 40px;
  --avatar-3xl-size: 46px;

  /* Per-size squircle radii */
  --avatar-xs-radius: 4px;
  --avatar-sm-radius: 5px;
  --avatar-md-radius: 5px;
  --avatar-lg-radius: 6px;
  --avatar-xl-radius: 6px;
  --avatar-2xl-radius: 8px;
  --avatar-3xl-radius: 8px;

  /* Per-size initials font sizes */
  --avatar-xs-font-size: 11px;
  --avatar-sm-font-size: 13px;
  --avatar-md-font-size: 14px;
  --avatar-lg-font-size: 14px;
  --avatar-xl-font-size: 16px;
  --avatar-2xl-font-size: 18px;
  --avatar-3xl-font-size: 20px;

  /* Per-size fallback icon sizes */
  --avatar-xs-icon-size: 10px;
  --avatar-sm-icon-size: 12px;
  --avatar-md-icon-size: 14px;
  --avatar-lg-icon-size: 16px;
  --avatar-xl-icon-size: 18px;
  --avatar-2xl-icon-size: 22px;
  --avatar-3xl-icon-size: 24px;

  /* Surfaces */
  --avatar-bg: var(--color-muted);
  --avatar-fg: var(--color-muted-foreground);

  /* Status badge shell — slot/prop content is the icon only */
  --avatar-status-size: 10px;
  --avatar-status-icon-size: 6px;
  --avatar-status-bg: var(--color-background);
  --avatar-status-ring: var(--color-background);
  --avatar-status-ring-width: 2px;
}

/* Avatar group component tokens — override these to customise avatar stacks. */
:root {
  --avatar-group-ring: var(--color-background);
  --avatar-group-ring-width: 2px;

  --avatar-group-overlap-xs: 2px;
  --avatar-group-overlap-sm: 4px;
  --avatar-group-overlap-md: 4px;
  --avatar-group-overlap-lg: 5px;
  --avatar-group-overlap-xl: 4px;
  --avatar-group-overlap-2xl: 6px;
  --avatar-group-overlap-3xl: 8px;

  --avatar-group-label-fg: var(--color-muted-foreground);

  --avatar-group-label-xs-font-size: 11px;
  --avatar-group-label-sm-font-size: 11px;
  --avatar-group-label-md-font-size: 14px;
  --avatar-group-label-lg-font-size: 14px;
  --avatar-group-label-xl-font-size: 16px;
  --avatar-group-label-2xl-font-size: 18px;
  --avatar-group-label-3xl-font-size: 20px;
}

/* Badge component tokens — override these to customise badges. */
:root {
  --badge-gap: 4px;
  --badge-radius: var(--radius-full);

  /* Size: sm */
  --badge-sm-py: 1px;
  --badge-sm-px: 6px;
  --badge-sm-font-size: 12px;
  --badge-sm-icon-size: 10px;

  /* Size: md */
  --badge-md-py: 3px;
  --badge-md-px: 6px;
  --badge-md-font-size: 12px;
  --badge-md-icon-size: 12px;

  /* Size: lg */
  --badge-lg-py: 4.5px;
  --badge-lg-px: 8px;
  --badge-lg-font-size: 13px;
  --badge-lg-icon-size: 12px;

  /* Theme: default */
  --badge-default-solid-bg: var(--color-primary);
  --badge-default-solid-fg: var(--color-primary-foreground);
  --badge-default-subtle-bg: var(--color-muted);
  --badge-default-subtle-fg: var(--color-muted-foreground);
  --badge-default-outline-border: color-mix(
    in oklch,
    var(--color-muted-foreground) 45%,
    var(--color-background)
  );
  --badge-default-outline-fg: var(--color-muted-foreground);
  --badge-default-ghost-fg: var(--color-muted-foreground);

  /* Theme: error */
  --badge-error-solid-bg: var(--color-error);
  --badge-error-solid-fg: var(--color-error-foreground);
  --badge-error-subtle-bg: var(--color-error-subtle);
  --badge-error-subtle-fg: var(--color-error);
  --badge-error-outline-border: color-mix(
    in oklch,
    var(--color-error) 35%,
    var(--color-background)
  );
  --badge-error-outline-fg: var(--color-error);
  --badge-error-ghost-fg: var(--color-error);

  /* Theme: warning */
  --badge-warning-solid-bg: var(--color-warning);
  --badge-warning-solid-fg: var(--color-warning-foreground);
  --badge-warning-subtle-bg: var(--color-warning-subtle);
  --badge-warning-subtle-fg: var(--color-warning);
  --badge-warning-outline-border: color-mix(
    in oklch,
    var(--color-warning) 45%,
    var(--color-background)
  );
  --badge-warning-outline-fg: var(--color-warning);
  --badge-warning-ghost-fg: var(--color-warning);

  /* Theme: success */
  --badge-success-solid-bg: var(--color-success);
  --badge-success-solid-fg: var(--color-success-foreground);
  --badge-success-subtle-bg: var(--color-success-subtle);
  --badge-success-subtle-fg: var(--color-success);
  --badge-success-outline-border: color-mix(
    in oklch,
    var(--color-success) 40%,
    var(--color-background)
  );
  --badge-success-outline-fg: var(--color-success);
  --badge-success-ghost-fg: var(--color-success);

  /* Theme: info */
  --badge-info-solid-bg: var(--color-info);
  --badge-info-solid-fg: var(--color-info-foreground);
  --badge-info-subtle-bg: var(--color-info-subtle);
  --badge-info-subtle-fg: var(--color-info);
  --badge-info-outline-border: color-mix(in oklch, var(--color-info) 40%, var(--color-background));
  --badge-info-outline-fg: var(--color-info);
  --badge-info-ghost-fg: var(--color-info);
}

/* Button component tokens — override these to customise the button. */
:root {
  /* Solid variant */
  --btn-solid-bg: var(--color-primary);
  --btn-solid-fg: var(--color-primary-foreground);
  --btn-solid-bg-hover: oklch(from var(--color-primary) calc(l - 0.06) c h);
  /* visual-button-shadow-anatomy: six-layer shadow for depth and polish */
  --btn-solid-shadow:
    0 0 0 0.5px oklch(0 0 0 / 0.2), inset 0 0 0 1px oklch(1 1 1 / 0.04),
    inset 0 1px 0 oklch(1 1 1 / 0.07), 0 1px 2px oklch(0 0 0 / 0.1), 0 2px 4px oklch(0 0 0 / 0.06),
    0 4px 8px oklch(0 0 0 / 0.03);

  /* Outline variant */
  --btn-outline-border: var(--color-border);
  --btn-outline-fg: var(--color-foreground);
  --btn-outline-bg-hover: var(--color-accent);

  /* Ghost variant */
  --btn-ghost-fg: var(--color-foreground);
  --btn-ghost-bg-hover: var(--color-accent);

  /* Link variant */
  --btn-link-fg: var(--color-primary);

  /* Shared */
  --btn-radius: var(--radius-md);
  --btn-ring: var(--color-ring);
  --btn-disabled-opacity: 0.5;

  /* Size: sm */
  --btn-sm-height: 32px;
  --btn-sm-px: 12px;
  --btn-sm-font-size: 13px;

  /* Size: md */
  --btn-md-height: 36px;
  --btn-md-px: 16px;
  --btn-md-font-size: 14px;

  /* Size: lg */
  --btn-lg-height: 40px;
  --btn-lg-px: 20px;
  --btn-lg-font-size: 15px;
}
